// ── JORDAN GRANT READER v1 — Node 1: Scan Grant_Inbox ──
const fs   = require('fs');
const path = require('path');

const INBOX      = '/data/Data/Grant_Inbox';
const PROCESSED  = '/data/Data/Grant_Inbox/.processed';
const raw        = $input.first().json;
const body       = raw.body || raw;

let processedFiles = [];
try {
  const logRaw = fs.readFileSync(PROCESSED, 'utf8');
  processedFiles = logRaw.split('\n').filter(Boolean);
} catch(e) {}

let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) {}
const entities  = ctx.entities  || {};
const founder   = ctx.founder   || {};
const deadlines = (ctx.deadlines || []).filter(d => {
  const st = (d.status || '').toUpperCase();
  return st !== 'FILED' && st !== 'COMPLETE' && st !== 'EXEMPT';
});

const eafProfile = [
  'ORGANIZATION: ' + ((entities.EAF || {}).name || 'KAI-Netics Equity & Autonomy Foundry'),
  'EIN: ' + ((entities.EAF || {}).ein || '41-4820296'),
  'TYPE: Maryland Nonstock Corp 501c3 pending',
  'PROGRAMS: CAKO 12-16 week drone operator certification | MONK tech access | Talent Pipeline Agreement',
  'FOUNDER: ' + (founder.name || 'Kevin Alexander Smith') + ' | ' + (founder.credentials || []).join(', '),
  'SERVICE AREA: Maryland, DC Metro, Northern Virginia',
  'ACTIVE DEADLINES: ' + deadlines.slice(0,5).map(d => d.item + ' → ' + d.date).join(' | ')
].join('\n');

const fpProfile = [
  'COMPANY: Kevin Alexander International LLC dba KAI-Netics',
  'EIN: 46-2432851 | Maryland LLC For-Profit',
  'CAPABILITIES: FAA Part 107 drone ops | Infrastructure inspection | CISSP cybersecurity consulting | Warehouse autonomous scanning | DFR/public safety',
  'NAICS: 488190, 541519, 541690',
  'FOUNDER CREDENTIALS: ' + (founder.credentials || []).join(', ')
].join('\n');

let targetFile = null;
let targetPath = null;
let isManual   = false;

if (body.filePath) {
  targetPath = body.filePath;
  targetFile = path.basename(body.filePath);
  isManual   = true;
} else {
  let files = [];
  try {
    files = fs.readdirSync(INBOX)
      .filter(f => !f.startsWith('.') && (f.endsWith('.txt') || f.endsWith('.md') || f.endsWith('.pdf') || f.endsWith('.docx')))
      .filter(f => !processedFiles.includes(f))
      .map(f => ({ name: f, mtime: fs.statSync(path.join(INBOX, f)).mtimeMs }))
      .sort((a, b) => b.mtime - a.mtime);
  } catch(e) { files = []; }

  if (files.length === 0) {
    return [{ json: { noFiles: true, message: 'Grant_Inbox is empty or all files already processed.', inbox: INBOX, eafProfile, fpProfile } }];
  }
  targetFile = files[0].name;
  targetPath = path.join(INBOX, targetFile);
}

let content = '';
try {
  if (targetPath.endsWith('.pdf')) {
    content = '[PDF_CONVERSION_NEEDED: ' + targetFile + ' — convert to .txt and re-drop into Grant_Inbox]';
  } else {
    content = fs.readFileSync(targetPath, 'utf8');
  }
} catch(e) {
  content = 'Could not read file: ' + e.message;
}

return [{ json: { noFiles: false, targetFile, targetPath, content, isManual, eafProfile, fpProfile, processedCount: processedFiles.length, inbox: INBOX } }];

const https = require('https');
const input = $input.first().json;

const requestBody = JSON.stringify({
  model:      'claude-sonnet-4-20250514',
  max_tokens: 4096,
  system:     input.systemMessage,
  messages:   [{ role: 'user', content: input.userMessage }]
});

const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.anthropic.com', port: 443,
    path: '/v1/messages', method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': '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',
      'anthropic-version': '2023-06-01',
      'Content-Length': Buffer.byteLength(requestBody)
    }
  }, (res) => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode, body: d })); });
  req.on('error', reject);
  req.write(requestBody);
  req.end();
});

let aiOutput = '';
try { aiOutput = JSON.parse(result.body).content[0].text || 'No response.'; }
catch(e) { aiOutput = result.body.substring(0, 500); }

return [{ json: Object.assign({}, input, { aiOutput, apiStatus: result.status }) }];

// ── Node 5: Parse Output + Save Report + Mark Processed ──
const fs        = require('fs');
const path      = require('path');
const input     = $input.first().json;
const aiOutput  = input.aiOutput || '';
const timestamp = new Date().toISOString();

const get = (key) => {
  const m = aiOutput.match(new RegExp(key + '[:\\s*\\*]+([^\\n]+)', 'i'));
  return m ? m[1].trim().replace(/\*\*/g, '') : null;
};

const funder       = get('FUNDER');
const program      = get('PROGRAM');
const deadline     = get('DEADLINE');
const awardRange   = get('AWARD RANGE');
const entityFit    = get('ENTITY FIT') || 'EAF';
const fitScoreRaw  = get('FIT SCORE');
const fitScore     = fitScoreRaw ? parseInt(fitScoreRaw) : null;
const fitRationale = get('FIT RATIONALE');
const alignment    = get('STRATEGIC ALIGNMENT');
const overlaps     = get('RELATIONSHIP OVERLAPS');
const blockers     = get('BLOCKERS');
const recAction    = get('RECOMMENDED ACTION');
const nextStep     = get('NEXT STEP');

const calMatch = aiOutput.match(/CALENDAR EVENT:[\s\S]*?(?=\n\n\n|$)/i);
const calBlock  = calMatch ? calMatch[0] : null;
const calSkip   = !calBlock || calBlock.includes('SKIP');

let calTitle = null, calDate = null, calDesc = null;
if (!calSkip && calBlock) {
  const getC = (key) => { const m = calBlock.match(new RegExp(key + '[:\\s]+([^\\n]+)', 'i')); return m ? m[1].trim() : null; };
  calTitle = getC('TITLE');
  calDate  = getC('DATE');
  calDesc  = getC('DESCRIPTION');
}

const validCalDate = calDate && /^\d{4}-\d{2}-\d{2}$/.test(calDate) && calDate !== 'SKIP' && calDate !== 'UNCONFIRMED';

const safeTime   = timestamp.replace(/[:.]/g, '-');
const safeName   = (input.targetFile || 'grant').replace(/[^a-zA-Z0-9]/g, '_').substring(0, 40);
const reportPath = '/data/Aidan_Outputs/Jordan/GrantReader_' + safeTime + '_' + safeName + '.txt';
fs.mkdirSync('/data/Aidan_Outputs/Jordan', { recursive: true });

const reportHeader = [
  'JORDAN GRANT READER v1',
  'File:      ' + input.targetFile,
  'Processed: ' + timestamp,
  'Funder:    ' + (funder    || 'See analysis'),
  'Program:   ' + (program   || 'See analysis'),
  'Deadline:  ' + (deadline  || 'UNCONFIRMED'),
  'Award:     ' + (awardRange|| 'N/A'),
  'Fit Score: ' + (fitScore  !== null ? fitScore + '%' : 'See analysis'),
  'Entity:    ' + entityFit,
  'Action:    ' + (recAction || 'REVIEW'),
  'Calendar:  ' + (validCalDate ? 'EVENT CREATED — ' + calDate : 'SKIPPED — ' + (calDate || 'no date extracted')),
  '',
  '─'.repeat(60),
  ''
].join('\n');

fs.writeFileSync(reportPath, reportHeader + aiOutput, 'utf8');

const PROCESSED = '/data/Data/Grant_Inbox/.processed';
try {
  const existing = fs.existsSync(PROCESSED) ? fs.readFileSync(PROCESSED, 'utf8') : '';
  if (!existing.includes(input.targetFile)) {
    fs.writeFileSync(PROCESSED, existing + input.targetFile + '\n', 'utf8');
  }
} catch(e) {}

return [{ json: Object.assign({}, input, {
  funder, program, deadline, awardRange, entityFit,
  fitScore, fitRationale, alignment, overlaps, blockers,
  recAction, nextStep, reportPath,
  calTitle, calDate: validCalDate ? calDate : null,
  calDesc, calSkip: !validCalDate, timestamp
}) }];

// ── Node 7: WhatsApp Delivery + Aidan Callback ──
const http  = require('http');
const input = $input.first().json;

const fitColor  = input.fitScore >= 80 ? '🟢' : input.fitScore >= 60 ? '🟡' : input.fitScore ? '🔴' : '⚪';
const calStatus = input.calSkip ? '📅 No deadline extracted' : '📅 Calendar event created — ' + input.calDate;
const blocker   = input.blockers && input.blockers.toUpperCase() !== 'NONE' ? '⚠ BLOCKERS: ' + input.blockers : '';

const msgLines = [
  'JORDAN GRANT READER v1',
  '─────────────────────────',
  '📄 ' + input.targetFile,
  '',
  'Funder:   ' + (input.funder   || 'See report'),
  'Program:  ' + (input.program  || 'See report'),
  'Deadline: ' + (input.deadline || 'UNCONFIRMED'),
  'Award:    ' + (input.awardRange || 'N/A'),
  'Entity:   ' + (input.entityFit || 'EAF'),
  '',
  fitColor + ' Fit: ' + (input.fitScore !== null ? input.fitScore + '%' : 'See report'),
  blocker,
  '→ ' + (input.recAction || 'REVIEW'),
  '→ Next: ' + (input.nextStep || 'See report'),
  '',
  calStatus,
  'Report: ' + input.reportPath
].filter(l => l !== null && l !== '').join('\n');

const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: msgLines } });
try {
  await new Promise((resolve) => {
    const req = http.request({
      hostname: 'host.docker.internal', port: 8081,
      path: '/message/sendText/Aidan', method: 'POST',
      headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) }
    }, (res) => { res.on('data', () => {}); res.on('end', resolve); });
    req.on('error', resolve);
    req.write(msgBody);
    req.end();
  });
} catch(e) {}

const cbBody = JSON.stringify({ agent: 'Jordan-GrantReader', summary: 'Grant Reader processed: ' + input.targetFile + ' | Fit: ' + (input.fitScore || '?') + '% | Action: ' + (input.recAction || 'REVIEW'), fitScore: input.fitScore, action: input.recAction, calCreated: !input.calSkip, calDate: input.calDate || null, timestamp: input.timestamp });
try {
  const cbReq = http.request({ hostname: 'host.docker.internal', port: 5678, path: '/webhook/aidan-callback', method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) } }, (res) => { res.on('data', () => {}); res.on('end', () => {}); });
  cbReq.on('error', () => {});
  cbReq.write(cbBody);
  cbReq.end();
} catch(e) {}

return [{ json: { success: true, agent: 'Jordan-GrantReader', version: 'v1', file: input.targetFile, fitScore: input.fitScore, action: input.recAction, calCreated: !input.calSkip, reportPath: input.reportPath } }];
